    // init.sh is materialized to /tmp/starry_init.sh at boot (see entry.rs); keep it out of argv.
    String::from(include_str!("init.sh"))
}

#[unsafe(no_mangle)]
fn main() {
    let script = build_init_sh_c_argument();
    let mut args = Vec::new();
    args.push(String::from("/bin/sh"));
    args.push(String::from("-c"));
    args.push(script);
    let envs = [];

    // Bootstrap kernel with init.sh + whitelist (embedded via include_str!).
    starry_kernel::entry::init(&args, &envs);
}

