use std::env;
use std::fs;
use std::path::PathBuf;

fn main() {
    let manifest = PathBuf::from(env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR"));
    let out_dir = PathBuf::from(env::var("OUT_DIR").expect("OUT_DIR"));
    let candidates = [
        manifest.join("ltp_whitelist.txt"),
        manifest.join("../src/ltp_whitelist.txt"),
        manifest.join("src/ltp_whitelist.txt"),
    ];
    let src = candidates
        .iter()
        .find(|p| {
            p.metadata()
                .map(|m| m.is_file() && m.len() > 0)
                .unwrap_or(false)
        })
        .unwrap_or_else(|| {
            panic!(
                "ltp_whitelist.txt missing or empty; tried: {}",
                candidates
                    .iter()
                    .map(|p| p.display().to_string())
                    .collect::<Vec<_>>()
                    .join(", ")
            );
        });
    let content = fs::read_to_string(src).expect("read ltp_whitelist.txt");
    if content.trim().is_empty() {
        panic!("ltp_whitelist.txt is empty: {}", src.display());
    }
    fs::write(out_dir.join("ltp_whitelist.txt"), content).expect("write OUT_DIR/ltp_whitelist.txt");
    println!("cargo:rerun-if-changed={}", src.display());
}

